% =========================================================================
% AI ACKNOWLEDGMENT: This code was generated by Claude (Anthropic) with
% inputs and direction from Peter Martin.
%
% Imager_CNN_RegLOSO.m  --  Leave-One-Session-Out CNN (x,y) REGRESSION
%
% The regression counterpart to Imager_CNN_LOSO.m and the head-to-head twin
% of ../mlp_python/run_mlp_regloso.py.  Same conv trunk, same LOSO protocol,
% same preprocessing -- ONLY the head changes:
%
%     fc(nClasses) -> softmax -> classification      (classifier)
%     fc(2)        -> regression (MSE on x,y inches) (this file)
%
% PREPROCESSING = pipeline v2: complex baseline subtraction ONLY (no
% per-session mean subtraction).  Set CNN_LOSO_MEANSUB=1 to re-enable the
% v1 mean subtraction as an ablation.  Per-session z-score (the KEY trick)
% is unchanged.
%
% TARGETS: true physical (x, y) inches parsed from the RnCmPp labels --
%     cell centre  x = (col-0.5)*1.0,  y = (row-0.5)*1.0   (origin top-left)
%     sub-position +/-0.375 in  (P1 TL, P2 TR, P3 BR, P4 BL)
% with the photo-digitized overrides from position_adjustments.json applied
% where the glandular insert blocked the exact corner spot:
%     CNN_LOSO_ADJUST_KEY = A3_Empty | A3_F4 | A3_F5   (empty has none)
%
% METRICS (per fold + LOSO mean/std), mirroring run_mlp_regloso.py.
% Error DISTANCE only -- predictions are never snapped to grid positions:
%     trial-level    : mean/median Euclidean error (in), % <=0.5in / <=1in
%     position-level : median predicted point over a position's trials,
%                      then that point's error (majority-vote analog)
%     spread         : per-position mean radial distance of the trial
%                      predictions from their median (confidence proxy)
%     stratified     : near-insert (photo-adjusted labels) vs exterior,
%                      so insert-region error never pollutes exterior stats
%     centroid       : predict-the-train-centroid baseline
%
% ENV VARS (same driver pattern as Imager_CNN_LOSO.m):
%     CNN_LOSO_PARENT, CNN_LOSO_SESSIONS, CNN_LOSO_SETLABEL,
%     CNN_LOSO_ANT_MODE, CNN_LOSO_PORTS, CNN_LOSO_REFL_ONLY,
%     CNN_LOSO_INPUT, CNN_LOSO_PORT_REMAP, CNN_LOSO_EPOCHS,
%     CNN_LOSO_ADJUST_KEY (new), CNN_LOSO_MEANSUB (new, ablation)
%
% Outputs: ../results/cnn_regloso_<tag>.json (+ .mat, bar + spatial figures).
% The reg prefix keeps these out of the classification table/figure builders.
% =========================================================================

clear; clc; close all;

fprintf('=========================================================\n');
fprintf('  Imager CNN  --  LOSO (x,y) REGRESSION (Hunter 4-port)\n');
fprintf('=========================================================\n\n');

%% -----------------------------------------------------------------------
%  CONFIG  (same tunable CNN hyper-parameters as the classifier)
%  ----------------------------------------------------------------------
cfg.LR           = 1e-3;
cfg.BatchSize    = 16;
cfg.Epochs       = 100;
cfg.Conv1        = 32;
cfg.Conv2        = 32;
cfg.FC1          = 64;
cfg.Dropout      = 0.3;
cfg.LRDropFactor = 0.5;
cfg.LRDropPeriod = 30;
cfg.showPlots    = false;

if ~isempty(getenv('CNN_LOSO_EPOCHS'))
    cfg.Epochs = str2double(getenv('CNN_LOSO_EPOCHS'));
    fprintf('[override] Epochs = %d\n', cfg.Epochs);
end

rng(42);

if usejava('desktop'), figVis = 'on'; else, figVis = 'off'; end

LOADER_DIR = 'C:\Users\peter\Desktop\EM Imaging\Imager Program';
if exist(fullfile(LOADER_DIR, 'loadHunterVnaFolder.m'), 'file')
    addpath(LOADER_DIR);
else
    warning('loadHunterVnaFolder.m not found in %s.', LOADER_DIR);
end

thisDir = fileparts(mfilename('fullpath'));
if isempty(thisDir), thisDir = pwd; end
resultsDir = fullfile(fileparts(thisDir), 'results');
if ~isfolder(resultsDir), mkdir(resultsDir); end

%% -----------------------------------------------------------------------
%  1. SELECT DATA
%  ----------------------------------------------------------------------
defaultParent = ['C:\Users\peter\Desktop\EM Imaging\BreastPhantom\HunterVNA\' ...
                 'DataMeasurements\Sam Antennas\MediumAntenna\Separated\June18'];
if ~isfolder(defaultParent), defaultParent = pwd; end

if ~isempty(getenv('CNN_LOSO_PARENT'))
    parentDir = getenv('CNN_LOSO_PARENT');
    fprintf('[override] parent folder = %s\n', parentDir);
else
    fprintf('Select the PARENT folder that contains this setup''s session subfolders.\n');
    parentDir = uigetdir(defaultParent, 'Select parent folder (holds session subfolders)');
    if isequal(parentDir, 0)
        fprintf('Cancelled.\n'); return;
    end
end

[sessions, sessNames] = loadAllSessions(parentDir);
nSess = numel(sessions);
if nSess < 2
    error('LOSO needs at least 2 sessions; found %d in %s', nSess, parentDir);
end
fprintf('\nLoaded %d sessions:\n', nSess);
for s = 1:nSess
    fprintf('   [%d] %-45s  %d positions, %d trials\n', s, sessNames{s}, ...
        numel(sessions{s}.posLabels), sessions{s}.trialCount);
end

[~, setupName] = fileparts(parentDir);
if isempty(setupName), setupName = 'setup'; end

% v2 preprocessing is the DEFAULT; CNN_LOSO_MEANSUB=1 re-enables v1 mean sub.
meanSub = strcmp(strtrim(getenv('CNN_LOSO_MEANSUB')), '1');
setLabel = strtrim(getenv('CNN_LOSO_SETLABEL'));
if isempty(setLabel), setLabel = sprintf('%dsess', nSess); end
