fprintf('Session set: %s   preproc: %s\n', setLabel, preproc);

%% -----------------------------------------------------------------------
%  2. ANTENNA SUBSET + TARGET ADJUSTMENTS
%  ----------------------------------------------------------------------
reflOnly = strcmp(strtrim(getenv('CNN_LOSO_REFL_ONLY')), '1');
if ~isempty(getenv('CNN_LOSO_ANT_MODE'))
    antennaMode = lower(strtrim(getenv('CNN_LOSO_ANT_MODE')));
    ports = sort(unique(str2num(getenv('CNN_LOSO_PORTS')))); %#ok<ST2NM>
    if strcmp(antennaMode, 'all') || isempty(ports), ports = 1:4; antennaMode = 'all'; end
    if reflOnly, antennaMode = 'refl'; end
