else
    antennaMode = 'all'; ports = 1:4;
    fprintf('No CNN_LOSO_ANT_MODE set -- defaulting to ALL antennas.\n');
end

[selRows, sparamNames, sparamPairs] = antennaRows(ports, reflOnly); %#ok<ASGLU>

inputMode = lower(strtrim(getenv('CNN_LOSO_INPUT')));
