N_TDR_BINS = 64;

% Photo-digitized true positions where the glandular insert blocked the
% exact corner (same file the spatial accuracy plots use).
adjKey = strtrim(getenv('CNN_LOSO_ADJUST_KEY'));
ADJ_JSON = ['C:\Users\peter\Desktop\EM Imaging\Research Paper\github_repo\' ...
            'detectable_change\A3_hunter\position_adjustments.json'];
adjMap = containers.Map('KeyType', 'char', 'ValueType', 'any');
if ~isempty(adjKey) && ~strcmpi(adjKey, 'none')
    if ~exist(ADJ_JSON, 'file')
        error('position_adjustments.json not found: %s', ADJ_JSON);
    end
    J = jsondecode(fileread(ADJ_JSON));
    if ~isfield(J, adjKey)
        error('adjust key "%s" not in %s (has: %s)', adjKey, ADJ_JSON, ...
              strjoin(fieldnames(J), ', '));
    end
    A = J.(adjKey);
    fn = fieldnames(A);
    for ii = 1:numel(fn)
        v = A.(fn{ii});
        adjMap(fn{ii}) = double(v(:)');
    end
    fprintf('Target adjustments [%s]: %d positions photo-corrected\n', adjKey, adjMap.Count);
else
    adjKey = 'none';
    fprintf('No target adjustments applied (CNN_LOSO_ADJUST_KEY unset/none).\n');
end

tag = sprintf('%s_%s_%s_%s_ant%s', matlab.lang.makeValidName(setupName), setLabel, ...
              inputMode, antennaMode, strrep(num2str(ports), '  ', '-'));
fprintf('Antenna mode: %s   ports [%s]   input=%s\n', upper(antennaMode), num2str(ports), inputMode);
fprintf('S-parameters used (%d): %s\n', numel(sparamNames), strjoin(sparamNames, ', '));

%% -----------------------------------------------------------------------
%  3. BUILD PER-SESSION SAMPLE TENSORS
%  ----------------------------------------------------------------------
fprintf('\n--- Building per-session samples ---\n');
built = cell(nSess, 1);
posSetPerSess = cell(nSess, 1);
for s = 1:nSess
    built{s} = buildSession(sessions{s}, sparamPairs, inputMode, N_TDR_BINS, meanSub);
    posSetPerSess{s} = unique(built{s}.posLabel);
    fprintf('   session %d: %d samples across %d positions\n', ...
        s, numel(built{s}.posLabel), numel(posSetPerSess{s}));
end

validPos = posSetPerSess{1};
for s = 2:nSess
    validPos = intersect(validPos, posSetPerSess{s});
end
validPos = sort(validPos);
nPos = numel(validPos);
if nPos < 2
    error('Fewer than 2 positions common to all sessions.');
end

% (x,y) inch target per valid position (canonical grid + photo overrides)
validXY = zeros(nPos, 2);
for p = 1:nPos
    validXY(p, :) = labelToXY(validPos{p}, adjMap);
end
% near-insert = the photo-adjusted labels (they hug the glandular insert)
nearInsert = arrayfun(@(p) isKey(adjMap, validPos{p}), (1:nPos)');
nAdjusted = sum(nearInsert);
fprintf('Common positions: %d   photo-adjusted (near-insert): %d\n', nPos, nAdjusted);

numSParamRows = size(built{1}.X, 1);
numFreqPoints = size(built{1}.X, 2);
fprintf('CNN input image: %d rows x %d cols  (input=%s)\n', numSParamRows, numFreqPoints, inputMode);

%% -----------------------------------------------------------------------
%  4. EXECUTION ENVIRONMENT
%  ----------------------------------------------------------------------
if strcmp(strtrim(getenv('CNN_LOSO_FORCE_CPU')), '1')
    execEnv = 'cpu';
    fprintf('\nCNN_LOSO_FORCE_CPU=1 -- training on CPU.\n');
elseif gpuDeviceCount > 0
    execEnv = 'gpu';
    fprintf('\nGPU detected (%s) -- training on GPU.\n', gpuDevice().Name);
else
    execEnv = 'cpu';
    fprintf('\nNo GPU -- training on CPU.\n');
end

%% -----------------------------------------------------------------------
%  5. LEAVE-ONE-SESSION-OUT LOOP
%  ----------------------------------------------------------------------
fprintf('\n=== %d-fold LEAVE-ONE-SESSION-OUT (regression) ===\n', nSess);
HALF_CELL_IN = 0.5;
folds = struct([]);
posErrAcc = zeros(nPos, nSess);   % per-fold median-point error per position
posSprAcc = zeros(nPos, nSess);   % per-fold prediction spread per position
posPredXAcc = nan(nPos, nSess);   % per-fold predicted median x per position
posPredYAcc = nan(nPos, nSess);   % per-fold predicted median y per position

for testS = 1:nSess
    trainS = setdiff(1:nSess, testS);
    t0 = tic;

    [XTrain, yTrain] = gatherSamples(built(trainS), validPos);
    [XTest,  yTest]  = gatherSamples(built(testS),  validPos);

    TTrain = labelsToXYMat(yTrain, adjMap);
    TTest  = labelsToXYMat(yTest,  adjMap);

    net = trainCNNReg(XTrain, TTrain, numSParamRows, numFreqPoints, cfg, execEnv);
    pred = double(predict(net, XTest));

    % ----- trial-level -----
    trialErr = vecnorm(pred - TTest, 2, 2);
    trial = errStats(trialErr, HALF_CELL_IN);

    % ----- position-level: median predicted point + prediction spread -----
    posErrs = nan(nPos, 1);
    posSprs = nan(nPos, 1);
    for p = 1:nPos
        mask = strcmp(yTest, validPos{p});
        if ~any(mask), continue; end
        P = pred(mask, :);
        med = median(P, 1);
        posErrs(p) = norm(med - validXY(p, :));
        posSprs(p) = mean(vecnorm(P - med, 2, 2));
        posErrAcc(p, testS) = posErrs(p);
        posSprAcc(p, testS) = posSprs(p);
        posPredXAcc(p, testS) = med(1); posPredYAcc(p, testS) = med(2);
    end
    have = ~isnan(posErrs);
    position = errStats(posErrs(have), HALF_CELL_IN);
    position.medianSpreadIn = median(posSprs(have));

    % ----- stratified: near-insert (photo-adjusted) vs exterior -----
    strat = struct();
    for g = 1:2
        if g == 1, sel = nearInsert & have; gname = 'nearInsert';
        else,      sel = ~nearInsert & have; gname = 'exterior'; end
        if any(sel)
            gs = errStats(posErrs(sel), HALF_CELL_IN);
            gs.medianSpreadIn = median(posSprs(sel));
            gs.n = sum(sel);
        else
            gs = struct('n', 0);
        end
        strat.(gname) = gs;
    end

    % ----- centroid baseline -----
    centroid = mean(TTrain, 1);
    baseErr = vecnorm(TTest - centroid, 2, 2);
    baseline = errStats(baseErr, HALF_CELL_IN);

    folds(testS).testSession      = sessNames{testS};
    folds(testS).trial            = trial;
    folds(testS).position         = position;
    folds(testS).stratified       = strat;
    folds(testS).baselineCentroid = baseline;

    if strat.nearInsert.n > 0
        niTxt = sprintf('near-insert med=%.3fin(n=%d)  ', ...
                        strat.nearInsert.medianErrIn, strat.nearInsert.n);
    else
        niTxt = '';
    end
    fprintf('  fold test=%d (%s):  trial med=%.3fin  pos med=%.3fin  <=0.5in %.0f%%  spread=%.3fin  %scentroid med=%.2fin  (%.1fs)\n', ...
        testS, sessNames{testS}, trial.medianErrIn, position.medianErrIn, ...
        position.pctWithinHalfIn, position.medianSpreadIn, niTxt, ...
        baseline.medianErrIn, toc(t0));
end

losoStat = @(fn) [mean(arrayfun(fn, folds)), std(arrayfun(fn, folds))];
losoPosMedianErr    = losoStat(@(f) f.position.medianErrIn);
losoPosMeanErr      = losoStat(@(f) f.position.meanErrIn);
losoPosPctHalfIn    = losoStat(@(f) f.position.pctWithinHalfIn);
losoPosPct1In       = losoStat(@(f) f.position.pctWithin1In);
losoPosMedianSpread = losoStat(@(f) f.position.medianSpreadIn);
losoTrialMedianErr  = losoStat(@(f) f.trial.medianErrIn);
losoTrialMeanErr    = losoStat(@(f) f.trial.meanErrIn);
losoCentroidMedian  = losoStat(@(f) f.baselineCentroid.medianErrIn);
losoNearInsertMedErr    = groupLoso(folds, 'nearInsert', 'medianErrIn');
losoNearInsertPctHalf   = groupLoso(folds, 'nearInsert', 'pctWithinHalfIn');
losoNearInsertMedSpread = groupLoso(folds, 'nearInsert', 'medianSpreadIn');
losoExteriorMedErr      = groupLoso(folds, 'exterior', 'medianErrIn');
losoExteriorPctHalf     = groupLoso(folds, 'exterior', 'pctWithinHalfIn');
losoExteriorMedSpread   = groupLoso(folds, 'exterior', 'medianSpreadIn');

fprintf('\n---------------------------------------------------------\n');
