result.losoPosMedianSpread = losoPosMedianSpread;
result.losoNearInsertMedianErr    = losoNearInsertMedErr;
result.losoNearInsertPctHalfIn    = losoNearInsertPctHalf;
result.losoNearInsertMedianSpread = losoNearInsertMedSpread;
result.losoExteriorMedianErr      = losoExteriorMedErr;
result.losoExteriorPctHalfIn      = losoExteriorPctHalf;
