% =========================================================================
%  LOCAL FUNCTIONS
% =========================================================================
function [sessions, names] = loadAllSessions(parentDir)
% Enumerate Hunter session subfolders under parentDir and load each.
    d = dir(parentDir);
    subs = d([d.isdir] & ~ismember({d.name}, {'.', '..'}));
    filt = strtrim(getenv('CNN_LOSO_SESSIONS'));
    if ~isempty(filt)
        toks = strsplit(filt, {' ', ','});
        toks = toks(~cellfun(@isempty, toks));
        keep = false(1, numel(subs));
        for ii = 1:numel(subs)
            for tt = 1:numel(toks)
                if contains(subs(ii).name, toks{tt}), keep(ii) = true; break; end
            end
        end
        subs = subs(keep);
        fprintf('[filter] CNN_LOSO_SESSIONS=%s -> %d matching session folders\n', filt, numel(subs));
    end
    remapStr = strtrim(getenv('CNN_LOSO_PORT_REMAP'));
    rowperm = [];
    if ~isempty(remapStr)
        R = str2num(remapStr); %#ok<ST2NM>
        rowperm = zeros(1, 32);
        for a = 1:4
            for b = 1:4
                nidx = (b-1)*4 + a;  oidx = (R(b)-1)*4 + R(a);
                rowperm(2*nidx-1) = 2*oidx-1;  rowperm(2*nidx) = 2*oidx;
            end
        end
        fprintf('[remap] CNN_LOSO_PORT_REMAP=%s (new<-old ports)\n', remapStr);
    end

    sessions = {}; names = {};
    for i = 1:numel(subs)
        p = fullfile(parentDir, subs(i).name);
        if isHunterSession(p)
            fprintf('Loading session: %s\n', subs(i).name);
            try
                L = loadHunterVnaFolder(p);
                if ~isempty(rowperm)
                    L = permuteSessionRows(L, rowperm);
                end
                sessions{end+1} = L;             %#ok<AGROW>
                names{end+1}    = subs(i).name;  %#ok<AGROW>
            catch ME
                fprintf('  SKIP (%s)\n', ME.message);
            end
        end
    end
    if isempty(sessions) && isHunterSession(parentDir)
        error(['Selected folder is a single session. Select the PARENT ' ...
               'folder that contains multiple session subfolders.']);
    end
end

function tf = isHunterSession(p)
    tf = ~isempty(dir(fullfile(p, 'R*C*P*_T*.csv')));
end

function L = permuteSessionRows(L, rowperm)
% Reorder the 32 S-parameter rows of a loaded session by rowperm.
    for p = 1:size(L.data, 1)
        for t = 2:size(L.data, 2)
            M = L.data{p, t};
            if ~isempty(M) && size(M, 1) == numel(rowperm)
                L.data{p, t} = M(rowperm, :);
            end
        end
    end
    if isfield(L, 'baseline') && size(L.baseline, 1) == numel(rowperm)
        L.baseline = L.baseline(rowperm, :);
    end
    if isfield(L, 'baselineAll') && ~isempty(L.baselineAll) ...
            && size(L.baselineAll, 1) == numel(rowperm)
        L.baselineAll = L.baselineAll(rowperm, :, :);
    end
end

function [rows, names, pairs] = antennaRows(ports, reflOnly)
% Map an antenna (port) list to row indices in the 32-row Hunter matrix.
    if nargin < 2, reflOnly = false; end
    rows = []; names = {}; pairs = [];
    for i = ports
        for j = ports
            if reflOnly && i ~= j, continue; end
            idx = (j-1)*4 + i;
            rows(end+1) = 2*idx-1;  %#ok<AGROW>
            rows(end+1) = 2*idx;    %#ok<AGROW>
            names{end+1} = sprintf('S%d%d', i, j);          %#ok<AGROW>
            pairs(end+1, :) = [2*idx-1, 2*idx];             %#ok<AGROW>
        end
    end
    [rows, ~] = sort(rows);
    names = unique(names, 'stable');
end

function S = buildSession(loaded, pairs, inputMode, nTdr, meanSub)
% MATCHED-to-MLP feature construction (v2 default: NO session-mean sub).
%   1. complex baseline subtraction   Y = S - S_baseline
%   2. per-session mean subtraction   ONLY if meanSub (v1 ablation)
%   3. raw | physics | tdr representation (identical to run_mlp_regloso.py)
%   4. per-session z-score (per pixel, across samples) -- the KEY trick
    data       = loaded.data;
    baseline   = loaded.baseline;
    nPos       = size(data, 1);
    trialCount = loaded.trialCount;
    nFreq      = loaded.numFreqPoints;
    K          = size(pairs, 1);

    baseC = zeros(K, nFreq);
    for k = 1:K
        baseC(k, :) = baseline(pairs(k,1), :) .* exp(1j * deg2rad(baseline(pairs(k,2), :)));
    end

    Yall = zeros(K, nFreq, nPos * trialCount);
    posLabel = cell(nPos * trialCount, 1);
    n = 0;
    for p = 1:nPos
        lbl = data{p, 1};
        for t = 1:trialCount
            raw = data{p, t+1};
            if isempty(raw) || any(isnan(raw(:))), continue; end
            n = n + 1;
            Sc = zeros(K, nFreq);
            for k = 1:K
                Sc(k, :) = raw(pairs(k,1), :) .* exp(1j * deg2rad(raw(pairs(k,2), :)));
            end
            Yall(:, :, n) = Sc - baseC;
            posLabel{n} = lbl;
        end
    end
    Yall = Yall(:, :, 1:n);
    posLabel = posLabel(1:n);

    if meanSub
        Yall = Yall - mean(Yall, 3);   % v1 ablation only
    end

    switch inputMode
        case 'raw',     nRows = 2 * K; W = nFreq;
        case 'physics', nRows = 5 * K; W = nFreq;
        case 'tdr',     nRows = K;     W = nTdr;
        otherwise, error('unknown CNN_LOSO_INPUT %s', inputMode);
    end
    X = zeros(nRows, W, 1, n);
    for i = 1:n
        block = zeros(nRows, W);
        for k = 1:K
            yv = Yall(k, :, i);
            env = abs(ifft(yv));
            switch inputMode
                case 'raw'
                    block((k-1)*2 + (1:2), :) = [abs(yv); angle(yv)];
                case 'tdr'
                    block(k, :) = env(1:nTdr);
                case 'physics'
                    envpad = zeros(1, nFreq); envpad(1:nTdr) = env(1:nTdr);
                    block((k-1)*5 + (1:5), :) = [abs(yv); angle(yv); real(yv); imag(yv); envpad];
            end
        end
        X(:, :, 1, i) = block;
    end

    if n > 1
        X = (X - mean(X, 4)) ./ (std(X, 0, 4) + 1e-8);
    end

    S.X = X;
    S.posLabel = posLabel;
end

function [X, y] = gatherSamples(builtCells, validPos)
    Xs = {}; ys = {};
    for c = 1:numel(builtCells)
        B = builtCells{c};
        keep = ismember(B.posLabel, validPos);
        Xs{end+1} = B.X(:, :, :, keep); %#ok<AGROW>
        ys{end+1} = B.posLabel(keep);   %#ok<AGROW>
    end
    X = cat(4, Xs{:});
    y = vertcat(ys{:});
end

function xy = labelToXY(lbl, adjMap)
% Canonical RnCmPp -> (x, y) inches (matches label_xy.py exactly), with
% photo-digitized overrides taking precedence.
    if isKey(adjMap, lbl)
        xy = adjMap(lbl); return;
    end
    tok = regexp(lbl, 'R(\d+)C(\d+)P(\d+)', 'tokens'); t = tok{1};
    r = str2double(t{1}); c = str2double(t{2}); p = str2double(t{3});
    sp = 0.375;                       % 0.5 half-cell - 0.125 half-divider
    off = [-sp -sp; +sp -sp; +sp +sp; -sp +sp];   % P1 TL, P2 TR, P3 BR, P4 BL
    xy = [(c - 0.5) + off(p, 1), (r - 0.5) + off(p, 2)];
end

function T = labelsToXYMat(labels, adjMap)
    T = zeros(numel(labels), 2);
    for i = 1:numel(labels)
        T(i, :) = labelToXY(labels{i}, adjMap);
    end
end

function M = errStats(err, halfCell)
    M.meanErrIn       = mean(err);
    M.medianErrIn     = median(err);
    M.pctWithinHalfIn = 100 * mean(err <= halfCell);
    M.pctWithin1In    = 100 * mean(err <= 1.0);
end

function v = groupLoso(folds, gname, field)
% [mean std] of a stratified-group stat across folds where the group is
% non-empty; [NaN NaN] if the group never appears (e.g. empty phantom).
    vals = [];
    for i = 1:numel(folds)
        g = folds(i).stratified.(gname);
        if isfield(g, 'n') && g.n > 0
            vals(end+1) = g.(field); %#ok<AGROW>
        end
    end
    if isempty(vals), v = [NaN NaN]; else, v = [mean(vals), std(vals)]; end
end

function net = trainCNNReg(XTrain, TTrain, nRows, nFreq, cfg, execEnv)
% SAME conv trunk as Imager_CNN_LOSO.m; head = fc(2) + regression (MSE on
% x,y inches).  No leakage: held-out session never seen during training.
    layers = [
        imageInputLayer([nRows nFreq 1], 'Normalization', 'zscore', 'Name', 'input')
        convolution2dLayer([min(4,nRows) 20], cfg.Conv1, 'Padding', 'same', 'Name', 'conv1')
        batchNormalizationLayer('Name', 'bn1')
        reluLayer('Name', 'relu1')
        convolution2dLayer([min(2,nRows) 10], cfg.Conv2, 'Padding', 'same', 'Name', 'conv2')
        batchNormalizationLayer('Name', 'bn2')
        reluLayer('Name', 'relu2')
        fullyConnectedLayer(cfg.FC1, 'Name', 'fc1')
        batchNormalizationLayer('Name', 'bn3')
        reluLayer('Name', 'relu3')
        dropoutLayer(cfg.Dropout, 'Name', 'dropout')
        fullyConnectedLayer(2, 'Name', 'fc_out')
        regressionLayer('Name', 'output')
    ];

    if cfg.showPlots, plt = 'training-progress'; else, plt = 'none'; end
    opts = trainingOptions('adam', ...
        'MaxEpochs', cfg.Epochs, ...
        'MiniBatchSize', cfg.BatchSize, ...
        'InitialLearnRate', cfg.LR, ...
        'LearnRateSchedule', 'piecewise', ...
        'LearnRateDropPeriod', cfg.LRDropPeriod, ...
        'LearnRateDropFactor', cfg.LRDropFactor, ...
        'Shuffle', 'every-epoch', ...
        'ExecutionEnvironment', execEnv, ...
        'Verbose', false, ...
        'Plots', plt);

    net = trainNetwork(XTrain, TTrain, layers, opts);
end
